insert into programs (goal, name, description, structure, is_template) values ('powerlifting', 'Powerlifting — Starting Template', '4 days/week squat/bench/deadlift periodization with simple linear progression across 4 weeks.', '{"weeks": [{"week": 1, "note": "Working sets at ~70% of current estimated 1RM. Increase load from last week if bar speed stayed fast.", "days": [{"day": 1, "label": "Day 1 \u2014 Squat", "exercises": [{"name": "Competition Squat", "sets": 5, "reps": "5", "rest": "3-4 min", "notes": "~70% e1RM"}, {"name": "Pause Squat", "sets": 3, "reps": "3", "rest": "3 min", "notes": ""}, {"name": "Leg Press", "sets": 3, "reps": "10", "rest": "90 sec", "notes": ""}, {"name": "Weighted Plank", "sets": 3, "reps": "45 sec", "rest": "45 sec", "notes": ""}]}, {"day": 2, "label": "Day 2 \u2014 Bench", "exercises": [{"name": "Competition Bench Press", "sets": 5, "reps": "5", "rest": "3-4 min", "notes": "~70% e1RM"}, {"name": "Close-Grip Bench Press", "sets": 3, "reps": "6", "rest": "2 min", "notes": ""}, {"name": "Barbell Row", "sets": 4, "reps": "8", "rest": "90 sec", "notes": ""}, {"name": "Triceps Pushdown", "sets": 3, "reps": "12", "rest": "60 sec", "notes": ""}]}, {"day": 3, "label": "Day 3 \u2014 Deadlift", "exercises": [{"name": "Competition Deadlift", "sets": 5, "reps": "3", "rest": "3-4 min", "notes": "~70% e1RM"}, {"name": "Deficit Deadlift", "sets": 3, "reps": "4", "rest": "3 min", "notes": ""}, {"name": "Front Squat", "sets": 3, "reps": "6", "rest": "2 min", "notes": ""}, {"name": "Back Extension", "sets": 3, "reps": "12", "rest": "60 sec", "notes": ""}]}, {"day": 4, "label": "Day 4 \u2014 Bench Volume + Accessories", "exercises": [{"name": "Bench Press", "sets": 4, "reps": "6", "rest": "2-3 min", "notes": "~60% e1RM, volume day"}, {"name": "Overhead Press", "sets": 3, "reps": "8", "rest": "90 sec", "notes": ""}, {"name": "Chin-Up", "sets": 3, "reps": "AMRAP", "rest": "90 sec", "notes": ""}, {"name": "Face Pull", "sets": 3, "reps": "15", "rest": "60 se